extends CharacterBody2D
class_name Player

## 简易状态枚举（当状态机不可用时的备选）
enum PlayerState { IDLE, MOVE, ATTACK, DODGE, SKILL }

## 移动参数
@export var move_speed: float = 300.0

## 攻击参数
@export var attack_range: float = 40.0
@export var attack_damage: int = 10

## 技能参数
@export var skill_scene: PackedScene

## 当前朝向
var facing_direction: Vector2 = Vector2.DOWN

## 当前状态
var current_state: PlayerState = PlayerState.IDLE

## 状态计时器
var state_timer: float = 0.0

## 闪避方向
var dodge_direction: Vector2 = Vector2.DOWN

## 引用
@onready var sprite: Sprite2D = $Sprite2D
@onready var collision_shape: CollisionShape2D = $CollisionShape2D
@onready var animation_player: AnimationPlayer = $AnimationPlayer
@onready var attack_hitbox: Area2D = $AttackHitbox
@onready var attack_hitbox_shape: CollisionShape2D = $AttackHitbox/CollisionShape2D

func _ready() -> void:
	# 设置碰撞体
	_setup_collisions()

	# 设置精灵
	if sprite and sprite.texture:
		sprite.scale = Vector2(0.5, 0.5)
	sprite.z_as_relative = false
	sprite.z_index = 10

func _setup_collisions() -> void:
	# 玩家碰撞体
	if collision_shape.shape == null:
		var circle = CircleShape2D.new()
		circle.radius = 12.0
		collision_shape.shape = circle

	# 攻击判定框
	if attack_hitbox_shape.shape == null:
		var rect = RectangleShape2D.new()
		rect.size = Vector2(24, 24)
		attack_hitbox_shape.shape = rect
	attack_hitbox_shape.disabled = false
	attack_hitbox.monitoring = false

func _physics_process(delta: float) -> void:
	match current_state:
		PlayerState.IDLE:
			_state_idle(delta)
		PlayerState.MOVE:
			_state_move(delta)
		PlayerState.ATTACK:
			_state_attack(delta)
		PlayerState.DODGE:
			_state_dodge(delta)
		PlayerState.SKILL:
			_state_skill(delta)

## ===== 状态逻辑 =====

func _state_idle(_delta: float) -> void:
	velocity = Vector2.ZERO
	move_and_slide()

	var input_dir = Input.get_vector("move_left", "move_right", "move_up", "move_down")

	if input_dir.length() > 0.1:
		_change_state(PlayerState.MOVE)
		return

	if Input.is_action_just_pressed("dodge"):
		_change_state(PlayerState.DODGE)
		return

	if Input.is_action_just_pressed("attack"):
		_change_state(PlayerState.ATTACK)
		return

	if Input.is_action_just_pressed("skill"):
		_change_state(PlayerState.SKILL)
		return

func _state_move(_delta: float) -> void:
	var input_dir = Input.get_vector("move_left", "move_right", "move_up", "move_down")

	if input_dir.length() < 0.1:
		_change_state(PlayerState.IDLE)
		return

	facing_direction = input_dir
	velocity = input_dir * move_speed
	move_and_slide()

	if Input.is_action_just_pressed("dodge"):
		_change_state(PlayerState.DODGE)
		return

	if Input.is_action_just_pressed("attack"):
		_change_state(PlayerState.ATTACK)
		return

	if Input.is_action_just_pressed("skill"):
		_change_state(PlayerState.SKILL)
		return

func _state_attack(delta: float) -> void:
	state_timer += delta

	if state_timer == delta:  # 刚进入的第一帧
		velocity = Vector2.ZERO
		var attack_dir = get_mouse_direction()
		facing_direction = attack_dir
		attack_hitbox.position = attack_dir * attack_range
		attack_hitbox.rotation = attack_dir.angle()
		attack_hitbox.monitoring = true
		if animation_player.has_animation("attack"):
			animation_player.play("attack")

	if state_timer >= 0.15:
		attack_hitbox.monitoring = false
		attack_hitbox.position = Vector2.ZERO

	if state_timer >= 0.3:
		_change_state(PlayerState.IDLE)

func _state_dodge(delta: float) -> void:
	state_timer += delta

	if state_timer == delta:  # 刚进入的第一帧
		var input_dir = Input.get_vector("move_left", "move_right", "move_up", "move_down")
		dodge_direction = input_dir if input_dir.length() > 0.1 else facing_direction
		dodge_direction = dodge_direction.normalized()

	velocity = dodge_direction * 600.0
	move_and_slide()

	if state_timer >= 0.35:
		_change_state(PlayerState.IDLE)

func _state_skill(delta: float) -> void:
	state_timer += delta

	if state_timer == delta:  # 刚进入的第一帧
		velocity = Vector2.ZERO
		_cast_skill()

	if state_timer >= 0.4:
		_change_state(PlayerState.IDLE)

## ===== 辅助方法 =====

func _change_state(new_state: PlayerState) -> void:
	current_state = new_state
	state_timer = 0.0

func get_mouse_direction() -> Vector2:
	return (get_global_mouse_position() - global_position).normalized()

func _cast_skill() -> void:
	if skill_scene == null:
		return

	var skill_dir = get_mouse_direction()
	facing_direction = skill_dir

	var skill_instance = skill_scene.instantiate() as Node2D
	get_tree().current_scene.add_child(skill_instance)

	skill_instance.global_position = global_position + skill_dir * 20.0
	if skill_instance.has_method("set_direction"):
		skill_instance.set_direction(skill_dir)

	if animation_player.has_animation("skill"):
		animation_player.play("skill")

